import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  ArrowUpRight,
  Mail,
  Sparkles,
  Layers,
  Clock,
  Terminal
} from 'lucide-react';

import Navbar from './components/Navbar';
import ServicesSection from './components/ServicesSection';
import ProjectsSection from './components/ProjectsSection';
import AboutSection from './components/AboutSection';
import AIArchitect from './components/AIArchitect';
import ContactSection from './components/ContactSection';

const TECH_STACK = [
  { name: "React.js", color: "hover:text-[#61DAFB] hover:drop-shadow-[0_0_8px_rgba(97,218,251,0.4)]" },
  { name: "Next.js", color: "hover:text-[#ffffff] hover:drop-shadow-[0_0_8px_rgba(255,255,255,0.4)]" },
  { name: "Tailwind CSS", color: "hover:text-[#38B2AC] hover:drop-shadow-[0_0_8px_rgba(56,178,172,0.4)]" },
  { name: "Node.js", color: "hover:text-[#339933] hover:drop-shadow-[0_0_8px_rgba(51,153,51,0.4)]" },
  { name: "PHP", color: "hover:text-[#777BB4] hover:drop-shadow-[0_0_8px_rgba(119,123,180,0.4)]" },
  { name: "MySQL", color: "hover:text-[#4479A1] hover:drop-shadow-[0_0_8px_rgba(68,121,161,0.4)]" },
  { name: "TypeScript", color: "hover:text-[#3178C6] hover:drop-shadow-[0_0_8px_rgba(49,120,198,0.4)]" },
  { name: "Framer Motion", color: "hover:text-[#0055FF] hover:drop-shadow-[0_0_8px_rgba(0,85,255,0.4)]" },
  { name: "MongoDB", color: "hover:text-[#47A248] hover:drop-shadow-[0_0_8px_rgba(71,162,72,0.4)]" },
  { name: "Figma", color: "hover:text-[#F24E1E] hover:drop-shadow-[0_0_8px_rgba(242,78,30,0.4)]" },
  { name: "GraphQL", color: "hover:text-[#E10098] hover:drop-shadow-[0_0_8px_rgba(225,0,152,0.4)]" },
  { name: "PostgreSQL", color: "hover:text-[#336791] hover:drop-shadow-[0_0_8px_rgba(51,103,145,0.4)]" }
];

const fadeInUp = {
  initial: { opacity: 0, y: 40 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 1, ease: [0.16, 1, 0.3, 1] }
};

const staggerContainer = {
  animate: {
    transition: {
      staggerChildren: 0.15
    }
  }
};

const AbstractLogo = ({ className }) => (
  <svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className={className}>
    <path d="M39 58 L44 38 L65 28 L52 48 Z" fill="currentColor" />
    <path d="M61 42 L56 62 L35 72 L48 52 Z" fill="currentColor" />
  </svg>
);

export default function App() {
  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen bg-[#000000] text-slate-300 font-sans selection:bg-primary selection:text-black relative overflow-x-hidden">

      <Navbar />

      {/* Premium Noise Overlay */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none mix-blend-overlay z-50"
        style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}>
      </div>



      {/* --- 1. HERO SECTION --- */}
      <section id="home" className="relative min-h-screen flex items-center pt-20 overflow-hidden">
        <div className="absolute top-1/4 -left-32 w-96 h-96 bg-white/5 rounded-full blur-[120px]"></div>
        <div className="absolute bottom-1/4 -right-32 w-96 h-96 bg-white/5 rounded-full blur-[120px]"></div>

        <motion.div
          variants={staggerContainer}
          initial="initial"
          whileInView="animate"
          viewport={{ once: true }}
          className="container mx-auto px-6 relative z-10 flex flex-col items-center text-center"
        >
          <motion.h1
            variants={fadeInUp}
            className="text-6xl md:text-8xl lg:text-[9rem] font-black tracking-[-0.04em] leading-[0.85] mb-8"
          >
            <span className="text-transparent bg-clip-text bg-gradient-to-b from-white via-white/90 to-white/40">ENGINEERING</span> <br />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary via-accent to-white animate-pulse-slow drop-shadow-2xl">
              PLATFORMS
            </span>
          </motion.h1>

          <motion.p
            variants={fadeInUp}
            className="text-base md:text-xl text-slate-400 max-w-2xl font-medium leading-relaxed mb-12 px-4"
          >
            NEXcode is a premium engineering studio. We partner with forward-thinking brands to build robust, scalable platforms and high-conversion digital experiences.
          </motion.p>

          <motion.div
            variants={fadeInUp}
            className="flex flex-col sm:flex-row gap-6 w-full sm:w-auto mt-8 items-center justify-center"
          >
            <button
              onClick={() => scrollTo('work')}
              className="group px-10 py-5 rounded-full bg-white text-black font-extrabold text-lg flex items-center justify-center gap-2 hover:bg-slate-100 transition-all shadow-[0_0_30px_rgba(255,255,255,0.2)] active:scale-95"
            >
              View Our Work
            </button>
            <button
              onClick={() => scrollTo('contact')}
              className="group px-10 py-5 rounded-full bg-transparent border border-white/20 text-white font-extrabold text-lg flex items-center justify-center gap-2 hover:bg-white/5 transition-all active:scale-95"
            >
              Start Project <ArrowUpRight size={22} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform duration-300" />
            </button>
          </motion.div>
        </motion.div>
      </section>

      {/* --- INFINITE MARQUEE --- */}
      <div className="relative flex overflow-x-hidden border-y border-white/[0.05] bg-black py-4 md:py-6 w-full group">
        <div className="pointer-events-none absolute inset-y-0 left-0 w-16 md:w-48 bg-gradient-to-r from-black via-black/80 to-transparent z-10"></div>
        <div className="pointer-events-none absolute inset-y-0 right-0 w-16 md:w-48 bg-gradient-to-l from-black via-black/80 to-transparent z-10"></div>

        <div className="animate-scroll-banner group-hover:[animation-play-state:paused] transition-all duration-300 flex items-center whitespace-nowrap">
          {[...TECH_STACK, ...TECH_STACK].map((tech, idx) => (
            <div key={idx} className="flex items-center mx-6 md:mx-10">
              <span className={`text-base md:text-xl font-black text-slate-800 uppercase tracking-[0.15em] transition-all duration-500 cursor-default ${tech.color}`}>
                {tech.name}
              </span>
              <span className="mx-6 md:mx-10 text-xs text-primary/20 animate-pulse">✦</span>
            </div>
          ))}
        </div>
      </div>

      <ServicesSection />
      <ProjectsSection />
      <AboutSection />
      <AIArchitect />
      <ContactSection />

      {/* --- FOOTER --- */}
      <footer className="border-t border-white/10 bg-black pt-16 pb-8 px-4 md:px-6">
        <div className="container mx-auto max-w-6xl">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-16">
            <div>
              <div className="flex items-center gap-3 mb-4 cursor-default">
                <AbstractLogo className="w-10 h-10 text-primary" />
                <span className="text-white font-bold text-2xl tracking-tight">NEXcode.</span>
              </div>
              <p className="text-slate-500 max-w-xs">Premium web engineering for visionary brands.</p>
            </div>

            <div className="flex gap-12">
              <div>
                <h4 className="text-white font-semibold mb-4">Navigation</h4>
                <div className="flex flex-col gap-2">
                  {['Expertise', 'Work', 'Agency'].map(item => (
                    <button key={item} onClick={() => scrollTo(item.toLowerCase())} className="text-slate-400 hover:text-transparent hover:bg-clip-text hover:bg-gradient-to-r hover:from-primary hover:to-accent text-left transition-all duration-300 max-w-max">{item}</button>
                  ))}
                </div>
              </div>
              <div>
                <h4 className="text-white font-semibold mb-4">Social</h4>
                <div className="flex flex-col gap-2">
                  {['Twitter', 'LinkedIn', 'GitHub'].map(item => (
                    <a key={item} href="#" className="text-slate-400 hover:text-transparent hover:bg-clip-text hover:bg-gradient-to-r hover:from-primary hover:to-accent transition-all duration-300 max-w-max">{item}</a>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-center gap-4 pt-8 border-t border-white/10">
            <p className="text-slate-600 text-sm">© {new Date().getFullYear()} NEXcode Web Studio. All rights reserved.</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

import React, { useState } from 'react';
import { Layers, Server, Code2, Rocket, ArrowRight, CheckCircle2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const phases = [
    {
        id: 'discovery',
        title: 'Strategy & Requirements',
        icon: <Layers size={24} />,
        description: 'Comprehensive analysis of business objectives and technical requirements. We establish clear project scopes, success metrics, and architectural foundations before writing any code.',
        points: ['Requirements Gathering', 'Systems Architecture Design', 'Feasibility & Risk Assessment', 'Project Roadmap & Milestones'],
        techStack: ['Jira / Linear', 'Figma', 'Miro', 'Notion']
    },
    {
        id: 'architecture',
        title: 'System Design',
        icon: <Server size={24} />,
        description: 'Designing resilient, scalable infrastructure optimized for security and performance. Our architecture ensures your platform seamlessly handles high concurrency and data volume.',
        points: ['Database Schema & ERD', 'REST/GraphQL API Design', 'Cloud Resource Allocation', 'Security & Compliance Audits'],
        techStack: ['PostgreSQL', 'Redis', 'Docker', 'AWS / GCP']
    },
    {
        id: 'development',
        title: 'Engineering & QA',
        icon: <Code2 size={24} />,
        description: 'Iterative, sprint-based development utilizing modern frameworks. Every module is subjected to rigorous automated testing and peer code reviews to guarantee enterprise-grade stability.',
        points: ['Component-Driven UI/UX', 'Microservices Architecture', 'Continuous Integration', 'Automated Unit & E2E Testing'],
        techStack: ['React / Next.js', 'Node.js / Python', 'Jest / Cypress', 'TypeScript']
    },
    {
        id: 'deployment',
        title: 'Deployment & Ops',
        icon: <Rocket size={24} />,
        description: 'Automated deployment pipelines and comprehensive observability. We ensure smooth delivery with reliable, zero-downtime releases and proactive infrastructure monitoring.',
        points: ['CI/CD Pipeline Configuration', 'Load Balancing & CDN', 'Real-time Telemetry & Logging', 'Disaster Recovery Protocols'],
        techStack: ['GitHub Actions', 'Kubernetes', 'Datadog / Sentry', 'Cloudflare']
    }
];

const AIArchitect = () => {
    const [activePhase, setActivePhase] = useState(phases[0]);

    return (
        <section id="architecture" className="py-24 px-4 md:px-6 relative overflow-hidden bg-black border-t border-white/5">
            {/* Background elements */}
            <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-primary/5 rounded-full blur-[120px] pointer-events-none translate-x-1/3 -translate-y-1/3"></div>
            <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-accent/5 rounded-full blur-[100px] pointer-events-none -translate-x-1/3 translate-y-1/3"></div>

            <div className="container mx-auto max-w-6xl relative z-10">
                <div className="text-center mb-16 md:mb-24">
                    <motion.h2 
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        className="text-4xl md:text-6xl font-black text-white tracking-tighter mb-6 uppercase"
                    >
                        Our Engineering <br />
                        <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-accent">Blueprint</span>
                    </motion.h2>
                    <motion.p 
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: 0.1 }}
                        className="text-slate-400 text-lg md:text-xl max-w-2xl mx-auto font-medium"
                    >
                        How we transform complex visions into scalable, high-performance digital reality. A flawless process from concept to deployment.
                    </motion.p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-8 items-stretch">
                    {/* Left: Phase Navigation */}
                    <div className="lg:col-span-5 flex flex-col gap-4">
                        {phases.map((phase, index) => {
                            const isActive = activePhase.id === phase.id;
                            return (
                                <motion.button
                                    key={phase.id}
                                    initial={{ opacity: 0, x: -20 }}
                                    whileInView={{ opacity: 1, x: 0 }}
                                    viewport={{ once: true }}
                                    transition={{ delay: index * 0.1 }}
                                    onClick={() => setActivePhase(phase)}
                                    className={`w-full text-left p-6 rounded-2xl border transition-all duration-300 flex items-center gap-6 group relative overflow-hidden ${
                                        isActive 
                                        ? 'bg-black border-primary/30 shadow-[0_0_30px_-5px_rgba(46,161,227,0.15)] z-10' 
                                        : 'bg-white/[0.02] border-white/5 hover:bg-white/[0.05] hover:border-white/10'
                                    }`}
                                >
                                    {isActive && (
                                        <motion.div 
                                            layoutId="activeIndicator" 
                                            className="absolute left-0 top-0 bottom-0 w-1.5 bg-gradient-to-b from-primary to-accent" 
                                        />
                                    )}

                                    <div className={`p-4 rounded-xl shrink-0 transition-colors duration-300 ${isActive ? 'bg-primary/10 text-primary' : 'bg-white/5 text-slate-400 group-hover:text-white'}`}>
                                        {phase.icon}
                                    </div>

                                    <div>
                                        <div className="text-xs font-bold text-slate-500 mb-1.5 tracking-wider uppercase">Phase 0{index + 1}</div>
                                        <h3 className={`text-lg font-bold transition-colors duration-300 ${isActive ? 'text-white' : 'text-slate-300 group-hover:text-white'}`}>
                                            {phase.title}
                                        </h3>
                                    </div>

                                    <ArrowRight className={`ml-auto shrink-0 transition-all duration-300 ${isActive ? 'text-primary opacity-100 translate-x-0' : 'text-slate-600 opacity-0 -translate-x-4 group-hover:opacity-100 group-hover:translate-x-0'}`} />
                                </motion.button>
                            );
                        })}
                    </div>

                    {/* Right: Phase Details */}
                    <div className="lg:col-span-7 relative min-h-[500px] flex md:min-h-auto">
                        <AnimatePresence mode="wait">
                            <motion.div
                                key={activePhase.id}
                                initial={{ opacity: 0, y: 20, scale: 0.95 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                exit={{ opacity: 0, y: -20, scale: 0.95 }}
                                transition={{ duration: 0.4, ease: "easeOut" }}
                                className="absolute inset-0 md:relative md:w-full bg-[#050505] border border-white/10 rounded-3xl p-8 md:p-12 flex flex-col shadow-2xl overflow-hidden"
                            >
                                {/* Decorative gradient blob inside the card */}
                                <div className="absolute top-0 right-0 w-64 h-64 bg-primary/10 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

                                <div className="relative z-10 mb-10">
                                    <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 text-white font-semibold text-xs mb-6 tracking-wide uppercase">
                                        <div className="w-2 h-2 rounded-full bg-accent animate-pulse"></div>
                                        Phase {phases.findIndex(p => p.id === activePhase.id) + 1} Active
                                    </div>
                                    <h3 className="text-3xl md:text-4xl font-black text-white mb-4 tracking-tight">
                                        {activePhase.title}
                                    </h3>
                                    <p className="text-slate-400 text-lg leading-relaxed max-w-xl">
                                        {activePhase.description}
                                    </p>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-10 mt-auto relative z-10">
                                    {/* Key Deliverables */}
                                    <div className="space-y-6">
                                        <h4 className="text-white font-bold flex items-center gap-2 uppercase tracking-widest text-xs text-slate-500">
                                            <CheckCircle2 size={16} className="text-primary" />
                                            Key Focus Areas
                                        </h4>
                                        <ul className="space-y-4">
                                            {activePhase.points.map((point, i) => (
                                                <li key={i} className="flex items-start gap-3 text-slate-300">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-white/30 mt-2 shrink-0"></div>
                                                    <span className="text-sm font-medium">{point}</span>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>

                                    {/* Tech Stack */}
                                    <div className="space-y-6">
                                        <h4 className="text-white font-bold flex items-center gap-2 uppercase tracking-widest text-xs text-slate-500">
                                            <Code2 size={16} className="text-accent" />
                                            Technologies
                                        </h4>
                                        <div className="flex flex-wrap gap-2.5">
                                            {activePhase.techStack.map((tech, i) => (
                                                <span 
                                                    key={i} 
                                                    className="px-3.5 py-1.5 rounded-lg bg-white/5 border border-white/10 text-slate-200 text-xs font-bold tracking-wide transition-colors hover:bg-white/10 cursor-default"
                                                >
                                                    {tech}
                                                </span>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </motion.div>
                        </AnimatePresence>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default AIArchitect;

